  let markdown = `# Code Analysis Report\n\n`
  markdown += `**Project:** ${project.name}\n`
  markdown += `**Repository:** ${project.github_url}\n`
  markdown += `**Generated:** ${timestamp}\n\n`

  markdown += `---\n\n`

  // Summary Section
  markdown += `## Summary\n\n`
  markdown += `| Metric | Value |\n`
  markdown += `|--------|-------|\n`
  markdown += `| Total Files | ${summary.total_files || 0} |\n`
  markdown += `| Lines of Code | ${(summary.total_lloc || summary.total_sloc || summary.loc || 0).toLocaleString()} |\n`
  markdown += `| Functions | ${summary.total_functions || 0} |\n`
  markdown += `| Classes | ${summary.total_classes || 0} |\n\n`

  // Language Distribution
  if (summary.languages && Object.keys(summary.languages).length > 0) {
    markdown += `## Language Distribution\n\n`
    markdown += `| Language | Files |\n`
    markdown += `|----------|-------|\n`

    Object.entries(summary.languages).forEach(([language, count]) => {
      const fileCount = typeof count === 'number' ? count : (count?.count || 0)
      markdown += `| ${language} | ${fileCount} |\n`
    })
    markdown += `\n`
  }

  // Complexity Analysis
  markdown += `## Complexity Analysis\n\n`
  const complexityDist = calculateComplexityDistribution(files)
  if (complexityDist) {
    markdown += `| Complexity Level | Files | Percentage |\n`
    markdown += `|-----------------|-------|------------|\n`
    markdown += `| Low (1-5) | ${complexityDist.low} | ${complexityDist.lowPercent}% |\n`
    markdown += `| Medium (6-10) | ${complexityDist.medium} | ${complexityDist.mediumPercent}% |\n`
    markdown += `| High (11-20) | ${complexityDist.high} | ${complexityDist.highPercent}% |\n`
    markdown += `| Very High (20+) | ${complexityDist.veryHigh} | ${complexityDist.veryHighPercent}% |\n\n`

    markdown += `**Maintainable Files:** ${complexityDist.low + complexityDist.medium}\n`
    markdown += `**Files Needing Review:** ${complexityDist.high + complexityDist.veryHigh}\n\n`
  }

  // File Details
  markdown += `## File Details\n\n`
  markdown += `| File | Lines | Complexity | Functions | Classes |\n`
  markdown += `|------|-------|------------|-----------|----------|\n`

  files.slice(0, 50).forEach(file => {
    const fileName = (file.file_path || file.path || 'Unknown').split('/').pop()
    const lines = file.metrics?.raw?.loc || file.lines || 0
    const complexity = file.metrics?.complexity?.cyclomatic || 0
    const functions = file.metrics?.functions || 0
    const classes = file.metrics?.classes || 0

    markdown += `| ${fileName} | ${lines} | ${complexity} | ${functions} | ${classes} |\n`
  })

  if (files.length > 50) {
    markdown += `\n*Showing first 50 files. Total: ${files.length} files*\n`
  }

  markdown += `\n---\n\n`
  markdown += `*Generated by CodeCompass - AI-Powered Code Analysis Tool*\n`

  return markdown
}

/**
 * Calculate complexity distribution from files
 */
const calculateComplexityDistribution = (files) => {
  if (!files || files.length === 0) return null

  const dist = { low: 0, medium: 0, high: 0, veryHigh: 0 }

  files.forEach(file => {
    const complexity = file.metrics?.complexity?.cyclomatic || 0
    if (complexity <= 5) dist.low++
    else if (complexity <= 10) dist.medium++
    else if (complexity <= 20) dist.high++
    else dist.veryHigh++
  })

  const total = files.length
  return {
    ...dist,
    lowPercent: ((dist.low / total) * 100).toFixed(1),
    mediumPercent: ((dist.medium / total) * 100).toFixed(1),
    highPercent: ((dist.high / total) * 100).toFixed(1),
    veryHighPercent: ((dist.veryHigh / total) * 100).toFixed(1)
  }
}

/**
 * Download file to user's computer
 */
export const downloadFile = (content, filename, mimeType) => {
  const blob = new Blob([content], { type: mimeType })
  const url = URL.createObjectURL(blob)
  const link = document.createElement('a')
  link.href = url
  link.download = filename
  document.body.appendChild(link)
  link.click()
  document.body.removeChild(link)
  URL.revokeObjectURL(url)
}

